    registrationLimit: "",
    registrationFee: "",
    tags: "",
  });

  const [customFields, setCustomFields] = useState([]);
  const [merchandiseItems, setMerchandiseItems] = useState([]);
  const [purchaseLimit, setPurchaseLimit] = useState(1);

  const handleChange = (e) => {
    setEventData({ ...eventData, [e.target.name]: e.target.value });
  };

  /* ================= NORMAL EVENT FORM BUILDER ================= */

  const addField = () => {
    setCustomFields([
      ...customFields,
      {
        id: Date.now(),
        label: "",
        type: "text",
        required: false,
      },
    ]);
  };

  const updateField = (id, key, value) => {
    setCustomFields((fields) =>
      fields.map((f) => (f.id === id ? { ...f, [key]: value } : f))
    );
  };

  const deleteField = (id) => {
    setCustomFields(customFields.filter((f) => f.id !== id));
  };

  /* ================= MERCHANDISE ================= */

  const addItem = () => {
    setMerchandiseItems([
      ...merchandiseItems,
      { name: "", sizes: "", colors: "", stock: 0 },
    ]);
  };

  const updateItem = (index, key, value) => {
    const updated = [...merchandiseItems];
    updated[index][key] = value;
    setMerchandiseItems(updated);
  };

  /* ================= SUBMIT ================= */

  const handleSubmit = async (status) => {
    try {
      await axios.post(
        "http://localhost:5000/api/events",
        {
          ...eventData,
          status,
          customFields: eventData.type === "normal" ? customFields : [],
          merchandiseConfig:
            eventData.type === "merchandise"
              ? { items: merchandiseItems, purchaseLimit }
              : null,
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      alert(`Event ${status} successfully`);
    } catch (err) {
      alert("Error creating event");
    }
  };

  return (
    <div className="create-container">
      <h1 className="page-title">Create Event</h1>

      <div className="section-card">
        <h2 className="section-title">Event Details</h2>

        <div className="form-group">
          <label>Event Name</label>
          <input name="name" value={eventData.name} onChange={handleChange} />
        </div>

        <div className="form-group">
          <label>Description</label>
          <textarea
            name="description"
            value={eventData.description}
            onChange={handleChange}
          />
        </div>

        <div className="form-group">
          <label>Event Type</label>
          <select name="type" value={eventData.type} onChange={handleChange}>
            <option value="normal">Normal Event</option>
            <option value="merchandise">Merchandise Event</option>
          </select>
        </div>

        {/* ================= NORMAL EVENT FORM ================= */}
        {eventData.type === "normal" && (
          <div className="form-section">
            <h3>Custom Registration Form</h3>
            <button className="add-btn" onClick={addField}>
              + Add Field
            </button>

            {customFields.map((field) => (
              <div key={field.id} className="form-builder-card">
                <div className="form-group">
                  <label>Field Label</label>
                  <input
                    value={field.label}
                    onChange={(e) =>
                      updateField(field.id, "label", e.target.value)
                    }
                  />
                </div>

                <div className="form-group">
                  <label>Field Type</label>
                  <select
                    value={field.type}
                    onChange={(e) =>
                      updateField(field.id, "type", e.target.value)
                    }
                  >
                    <option value="text">Text</option>
                    <option value="dropdown">Dropdown</option>
                    <option value="checkbox">Checkbox</option>
                    <option value="file">File Upload</option>
                  </select>
                </div>

                <div className="checkbox-row">
                  <input
                    type="checkbox"
                    checked={field.required}
                    onChange={(e) =>
                      updateField(field.id, "required", e.target.checked)
                    }
                  />
                  <span>Required</span>
                </div>

                <button
                  className="delete-btn"
                  onClick={() => deleteField(field.id)}
                >
                  Delete Field
                </button>
              </div>
            ))}
          </div>
        )}

        {/* ================= MERCHANDISE ================= */}
        {eventData.type === "merchandise" && (
          <div className="form-section">
            <h3>Merchandise Items</h3>
            <button className="add-btn" onClick={addItem}>
              + Add Item
            </button>

            {merchandiseItems.map((item, index) => (
              <div key={index} className="form-builder-card">
                <div className="form-group">
                  <label>Item Name</label>
                  <input
                    onChange={(e) =>
                      updateItem(index, "name", e.target.value)
                    }
                  />
                </div>

                <div className="form-group">
                  <label>Sizes</label>
                  <input
                    onChange={(e) =>
                      updateItem(index, "sizes", e.target.value)
                    }
                  />
                </div>

                <div className="form-group">
                  <label>Colors</label>
                  <input
                    onChange={(e) =>
                      updateItem(index, "colors", e.target.value)
                    }
                  />
                </div>

                <div className="form-group">
                  <label>Stock</label>
                  <input
                    type="number"
                    onChange={(e) =>
                      updateItem(index, "stock", e.target.value)
                    }
                  />
                </div>
              </div>
            ))}

            <div className="form-group">
              <label>Purchase Limit Per Participant</label>
              <input
                type="number"
                value={purchaseLimit}
                onChange={(e) => setPurchaseLimit(e.target.value)}
              />
            </div>
          </div>
        )}

        {/* Buttons */}
        <div className="button-row">
          <button
            className="draft-btn"
            onClick={() => handleSubmit("draft")}
          >
            Save Draft
          </button>
          <button
            className="publish-btn"
            onClick={() => handleSubmit("published")}
          >
            Publish Event
          </button>
        </div>
      </div>
    </div>
  );
};

export default CreateEvent;
